import numpy as np

def rnn_forward(input_sequence: list[list[float]], initial_hidden_state: list[float], Wx: list[list[float]], Wh: list[list[float]], b: list[float]) -> list[float]:
    Wx = np.array(Wx)           # shape: (hidden_size, input_size)
    Wh = np.array(Wh)           # shape: (hidden_size, hidden_size)
    b  = np.array(b)            # shape: (hidden_size,)
    h  = np.array(initial_hidden_state, dtype=float)

    for x in input_sequence:
        x = np.array(x)
        h = np.tanh(Wx @ x + Wh @ h + b)

    return np.round(h, 4).tolist()
